name = "fastmcp-console"
version = "0.1.0"
edition = "2024"
description = "Rich console output for FastMCP servers"
license = "MIT"
repository = "https://github.com/Dicklesworthstone/fastmcp_rust"

[dependencies]
rich_rust = { path = "/dp/rich_rust" }  # Or git dependency
log = "0.4"

[features]
default = []
full = ["rich_rust/full"]  # Include syntax, markdown, json features
syntax = ["rich_rust/syntax"]
markdown = ["rich_rust/markdown"]
json = ["rich_rust/json"]

[lints]
workspace = true
