//! Integration tests for tags functionality

use fastmcp_server::{Server, ServerBuilder};
use fastmcp_protocol::types::*;

#[tokio::test]
async fn test_tagged_tools_appear_in_list_response() {
    let server = ServerBuilder::new("test", "1.0")
        .tool(tagged_tool("search", &["api", "public"]))
        .tool(tagged_tool("internal", &["private"]))
        .build();

    let result = server.list_tools().await.unwrap();

    let search_tool = result.tools.iter().find(|t| t.name == "search").unwrap();
    assert_eq!(search_tool.tags, vec!["api", "public"]);

    let internal_tool = result.tools.iter().find(|t| t.name == "internal").unwrap();
    assert_eq!(internal_tool.tags, vec!["private"]);
}

#[tokio::test]
async fn test_macro_generated_tool_has_tags() {
    #[tool(tags = ["macro", "test"])]
    async fn macro_tool() -> String {
        "result".into()
    }

    let server = ServerBuilder::new("test", "1.0")
        .tool(macro_tool)
        .build();

    let result = server.list_tools().await.unwrap();
    let tool = result.tools.first().unwrap();
    assert_eq!(tool.tags, vec!["macro", "test"]);
}
